#include <stdio.h>
#include <limits.h>

int maxEnergy(int** grid, int N) {
    int max = INT_MIN;
    int** dp = (int**)malloc(N * sizeof(int*));
    for (int i = 0; i < N; i++) {
        dp[i] = (int*)malloc(N * sizeof(int));
    }
    dp[0][0] = grid[0][0];
    for (int i = 1; i < N; i++) {
        dp[i][0] = dp[i-1][0] ^ grid[i][0];
        dp[0][i] = dp[0][i-1] ^ grid[0][i];
    }
    for (int i = 1; i < N; i++) {
        for (int j = 1; j < N; j++) {
            dp[i][j] = (dp[i-1][j] ^ grid[i][j]) > (dp[i][j-1] ^ grid[i][j]) ? dp[i-1][j] ^ grid[i][j] : dp[i][j-1] ^ grid[i][j];
        }
    }
    max = dp[N-1][N-1];
    for (int i = 0; i < N; i++) {
        free(dp[i]);
    }
    free(dp);
    return max;
}

int main() {
    int N;
    scanf("%d", &N);
    int** grid = (int**)malloc(N * sizeof(int*));
    for (int i = 0; i < N; i++) {
        grid[i] = (int*)malloc(N * sizeof(int));
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            scanf("%d", &grid[i][j]);
        }
    }
    printf("%d\n", maxEnergy(grid, N));
    for (int i = 0; i < N; i++) {
        free(grid[i]);
    }
    free(grid);
    return 0;
}

